import { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import {
  FiGrid, FiHeart, FiHome, FiLogOut, FiMenu, FiPackage, FiSearch,
  FiShoppingCart, FiUser, FiX,
} from 'react-icons/fi';
import { useApp } from '../../context/AppContext';
import { BRAND, HOME_CATEGORIES, UI_TEXT, USER_NAV } from '../../constants/labels';
import { ROUTE, ROUTES } from '../../constants/routes';

const ICONS = {
  home: FiHome,
  orders: FiPackage,
  wishlist: FiHeart,
  cart: FiShoppingCart,
  profile: FiUser,
};

const Navbar = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const { totalItems, wishlist, user, logout } = useApp();
  const navigate = useNavigate();
  const isAdmin = user?.role === 'ADMIN';
  const initials = useMemo(() => user?.name?.split(' ').map(part => part[0]).join('').slice(0, 2).toUpperCase() || '?', [user?.name]);

  const handleSearch = (event) => {
    event.preventDefault();
    const q = searchQuery.trim();
    if (q) navigate(ROUTE.search(q));
  };

  const categoryNav = useMemo(() => HOME_CATEGORIES.map(category => ({
    id: category.id,
    name: category.label,
    route: category.id === 'All' ? ROUTES.HOME : ROUTE.category(category.id),
  })), []);

  const visibleNav = USER_NAV.filter(item => {
    if (isAdmin && ['orders', 'wishlist', 'cart'].includes(item.key)) return false;
    if (!user && ['orders', 'wishlist', 'cart', 'profile'].includes(item.key)) return false;
    return true;
  });

  return (
    <header
      style={{
        background: 'var(--bg-main)',
        backdropFilter: 'blur(22px) saturate(170%)',
        borderBottom: '1.5px solid var(--border-subtle)',
        boxShadow: 'var(--shadow-sm)',
        position: 'sticky',
        top: 0,
        zIndex: 100,
      }}
    >
      <div className="mx-auto flex h-16 max-w-7xl items-center gap-3 px-3 sm:px-4">
        <motion.div whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }} className="shrink-0">
          <Link to={ROUTES.HOME} aria-label={BRAND.name} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <img src="/logo.png" alt="" style={{ width: 34, height: 34, borderRadius: 'var(--r-sm)', objectFit: 'contain', background: 'var(--bg-raised)', border: '1px solid var(--primary-border)' }} />
            <span style={{ display: 'flex', alignItems: 'baseline', gap: 0 }}>
            <span style={{ color: 'var(--primary)', fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 22 }}>{BRAND.nameEco}</span>
            <span style={{ color: 'var(--text-primary)', fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 22 }}>{BRAND.nameMart}</span>
            </span>
          </Link>
        </motion.div>

        <form onSubmit={handleSearch} className="hidden flex-1 sm:flex">
          <div
            className="mx-auto flex w-full max-w-[420px] items-center gap-2 px-4"
            style={{
              background: 'var(--bg-raised)',
              border: '1.5px solid var(--border-default)',
              borderRadius: 'var(--r-full)',
              flexGrow: 1,
            }}
          >
            <FiSearch size={16} color="var(--text-muted)" />
            <input
              value={searchQuery}
              onChange={event => setSearchQuery(event.target.value)}
              placeholder={UI_TEXT.searchPlaceholder}
              style={{ background: 'transparent', border: 0, boxShadow: 'none', padding: '10px 0' }}
            />
          </div>
        </form>

        <nav className="ml-auto flex items-center gap-2 text-sm font-bold">
          {!isAdmin && (
            <motion.div whileHover={{ scale: 1.1, background: 'var(--accent-warm)' }} whileTap={{ scale: 0.9 }} style={{ borderRadius: '50%' }}>
              <Link to={ROUTES.WISHLIST} aria-label="Wishlist" style={{ width: 40, height: 40, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', color: 'var(--text-primary)' }}>
                <FiHeart />
                {wishlist.length > 0 && <span style={{ position: 'absolute', top: -4, right: -4, width: 18, height: 18, borderRadius: '50%', background: 'var(--primary)', color: 'var(--text-primary)', fontFamily: 'var(--font-mono)', fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', animation: 'pulse-coral 1.5s ease-in-out 3' }}>{wishlist.length}</span>}
              </Link>
            </motion.div>
          )}

          {!isAdmin && (
            <motion.div whileHover={{ scale: 1.1, background: 'var(--accent-warm)' }} whileTap={{ scale: 0.9 }} style={{ borderRadius: '50%' }}>
              <Link to={ROUTES.CART} aria-label="Cart" style={{ width: 40, height: 40, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', color: 'var(--text-primary)' }}>
                <FiShoppingCart />
                {totalItems > 0 && <span key={totalItems} style={{ position: 'absolute', top: -4, right: -4, width: 18, height: 18, borderRadius: '50%', background: 'var(--primary)', color: 'var(--text-primary)', fontFamily: 'var(--font-mono)', fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center', animation: 'pulse-coral 1.5s ease-in-out 3' }}>{totalItems}</span>}
              </Link>
            </motion.div>
          )}

          <div className="relative">
            <motion.button
              type="button"
              whileHover={{ scale: 1.05, background: 'var(--accent-warm)' }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowUserMenu(value => !value)}
              style={{ width: 40, height: 40, borderRadius: '50%', color: 'var(--text-primary)', background: 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 800 }}
            >
              {user ? initials : <FiUser />}
            </motion.button>
            <AnimatePresence>
              {showUserMenu && (
                <motion.div
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: 8 }}
                  className="absolute right-0 top-12 z-50 w-64 overflow-hidden"
                  style={{ borderRadius: 'var(--r-md)', border: '1px solid var(--border-subtle)', background: 'var(--bg-surface)', boxShadow: 'var(--shadow-lg)' }}
                >
                  {!user ? (
                    <div style={{ padding: 16 }}>
                      <p style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{UI_TEXT.authNewUser}</p>
                      <p style={{ marginTop: 4, fontSize: 12 }}>{UI_TEXT.authMenuSub}</p>
                      <Link to={ROUTES.LOGIN} onClick={() => setShowUserMenu(false)} className="btn-primary" style={{ width: '100%', marginTop: 12 }}>{UI_TEXT.loginOrSignup}</Link>
                    </div>
                  ) : (
                    <div style={{ padding: '8px 0' }}>
                      <div style={{ borderBottom: '1px solid var(--border-subtle)', padding: '12px 16px' }}>
                        <div style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{user.name}</div>
                        <div style={{ color: 'var(--text-muted)', fontSize: 12 }}>{user.email}</div>
                        <div style={{ color: 'var(--primary)', fontSize: 12, fontWeight: 800 }}>{user.role}</div>
                      </div>
                      {isAdmin && <Link to={ROUTES.ADMIN_DASHBOARD} onClick={() => setShowUserMenu(false)} className="block px-4 py-2.5 hover:bg-[var(--accent-warm)]">{UI_TEXT.adminDashboard}</Link>}
                      {visibleNav.map(item => <Link key={item.key} to={item.route} onClick={() => setShowUserMenu(false)} className="block px-4 py-2.5 hover:bg-[var(--accent-warm)]">{item.label}</Link>)}
                      <button onClick={logout} className="flex w-full items-center gap-2 px-4 py-2.5 text-left text-[var(--error)] hover:bg-[var(--error-bg)]"><FiLogOut /> {UI_TEXT.logout}</button>
                    </div>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          <button className="rounded-md p-2 sm:hidden" onClick={() => setMobileMenuOpen(value => !value)}>{mobileMenuOpen ? <FiX size={24} /> : <FiMenu size={24} />}</button>
        </nav>
      </div>

      <form onSubmit={handleSearch} className="px-3 pb-3 sm:hidden">
        <div className="flex items-center gap-2 px-3" style={{ background: 'var(--bg-raised)', border: '1.5px solid var(--border-default)', borderRadius: 'var(--r-full)' }}>
          <FiSearch size={16} color="var(--text-muted)" />
          <input value={searchQuery} onChange={event => setSearchQuery(event.target.value)} placeholder={UI_TEXT.mobileSearchPlaceholder} style={{ background: 'transparent', border: 0, boxShadow: 'none', padding: '10px 0' }} />
        </div>
      </form>

      <div style={{ borderTop: '1px solid var(--border-subtle)', background: 'var(--bg-glass)' }}>
        <div className="hide-scrollbar mx-auto flex h-12 max-w-7xl items-center gap-2 overflow-x-auto px-3 sm:px-4">
          {categoryNav.slice(0, 6).map(category => (
            <Link key={category.id} to={category.route} className="category-pill">
              <FiGrid size={14} /> {category.name}
            </Link>
          ))}
        </div>
      </div>

      <AnimatePresence>
        {mobileMenuOpen && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setMobileMenuOpen(false)} style={{ position: 'fixed', inset: 0, background: 'var(--bg-glass-hover)', backdropFilter: 'blur(4px)', zIndex: 90 }} />
            <motion.aside
              initial={{ x: 280 }}
              animate={{ x: 0 }}
              exit={{ x: 280 }}
              transition={{ type: 'spring', stiffness: 340, damping: 30 }}
              style={{ position: 'fixed', top: 0, right: 0, bottom: 0, width: 280, background: 'var(--bg-surface)', zIndex: 101, boxShadow: 'var(--shadow-xl)', paddingTop: 18 }}
            >
              <div style={{ padding: '0 18px 14px', borderBottom: '1px solid var(--border-subtle)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <strong>{BRAND.name}</strong>
                <button onClick={() => setMobileMenuOpen(false)}><FiX /></button>
              </div>
              {visibleNav.map(item => {
                const Icon = ICONS[item.icon] || FiGrid;
                return <Link key={item.key} to={item.route} onClick={() => setMobileMenuOpen(false)} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '14px 18px', color: 'var(--text-primary)', borderBottom: '1px solid var(--border-subtle)' }}><Icon /> {item.label}</Link>;
              })}
              {categoryNav.map(category => <Link key={category.id} to={category.route} onClick={() => setMobileMenuOpen(false)} style={{ display: 'block', padding: '12px 18px', color: 'var(--text-secondary)' }}>{category.name}</Link>)}
            </motion.aside>
          </>
        )}
      </AnimatePresence>
    </header>
  );
};

export default Navbar;
