import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useMemo, useState } from 'react';
import { BRAND } from '../../constants/labels';

const PARTICLE_COUNT = 38;

const letterVariants = {
  hidden: { y: 40, opacity: 0 },
  visible: (i) => ({
    y: 0,
    opacity: 1,
    transition: {
      delay: 0.35 + i * 0.055,
      type: 'spring',
      stiffness: 200,
      damping: 20,
    },
  }),
};

export default function SplashScreen() {
  const [progress, setProgress] = useState(0);

  const particles = useMemo(() => Array.from({ length: PARTICLE_COUNT }, (_, id) => ({
    id,
    x: Math.random() * 100,
    delay: Math.random() * 2,
    size: Math.random() * 3 + 1,
    duration: Math.random() * 3 + 2,
  })), []);

  useEffect(() => {
    const start = Date.now();
    const interval = setInterval(() => {
      const elapsed = Date.now() - start;
      const p = Math.min((elapsed / 2000) * 100, 100);
      setProgress(p);
      if (p >= 100) clearInterval(interval);
    }, 16);
    return () => clearInterval(interval);
  }, []);

  return (
    <AnimatePresence>
      <motion.div
        exit={{ opacity: 0, scale: 1.05, filter: 'blur(5px)', transition: { duration: 0.42 } }}
        style={{
          position: 'fixed',
          inset: 0,
          background: 'var(--bg-void)',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 9999,
          overflow: 'hidden',
          fontFamily: 'var(--font-display)',
          color: 'var(--text-primary)',
        }}
      >
        <div
          style={{
            position: 'absolute',
            inset: 0,
            opacity: 0.025,
            backgroundImage: 'repeating-linear-gradient(45deg,var(--primary) 0,var(--primary) 1px,transparent 1px,transparent 44px)',
          }}
        />

        <motion.div
          initial={{ opacity: 0, scale: 0.4 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ delay: 0.8, duration: 1.4, ease: 'easeOut' }}
          style={{
            position: 'absolute',
            width: 520,
            height: 520,
            borderRadius: '50%',
            background: 'radial-gradient(circle,var(--primary-glow) 0%,var(--primary-subtle) 45%,transparent 68%)',
            pointerEvents: 'none',
          }}
        />

        {particles.map((p) => (
          <motion.div
            key={p.id}
            style={{
              position: 'absolute',
              left: `${p.x}%`,
              bottom: '-10px',
              width: p.size,
              height: p.size,
              borderRadius: '50%',
              background: p.id % 3 === 0 ? 'var(--primary-bright)' : 'var(--primary)',
              opacity: 0.45,
              filter: 'blur(0.2px)',
            }}
            animate={{ y: [0, -window.innerHeight - 20], opacity: [0, 0.6, 0] }}
            transition={{ duration: p.duration, delay: p.delay, repeat: Infinity, ease: 'linear' }}
          />
        ))}

        <motion.div
          initial={{ scale: 0.3, opacity: 0, rotate: -10 }}
          animate={{ scale: 1, opacity: 1, rotate: 0 }}
          transition={{ type: 'spring', stiffness: 180, damping: 15 }}
          style={{
            width: 72,
            height: 72,
            marginBottom: 24,
            position: 'relative',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            borderRadius: 20,
            background: 'linear-gradient(135deg,var(--primary) 0%,var(--primary-dim) 100%)',
            boxShadow: 'var(--shadow-orange)',
          }}
        >
          <motion.div
            animate={{ rotate: 360 }}
            transition={{ duration: 9, repeat: Infinity, ease: 'linear' }}
            style={{
              position: 'absolute',
              inset: -8,
              borderRadius: 28,
              border: '1px solid transparent',
              borderTopColor: 'var(--primary-border)',
              borderRightColor: 'var(--primary-glow)',
            }}
          />
          <img src="/logo.png" alt={BRAND.name} style={{ width: 54, height: 54, objectFit: 'contain', borderRadius: 16 }} />
        </motion.div>

        <div style={{ display: 'flex', overflow: 'hidden', marginBottom: 8 }}>
          {BRAND.name.split('').map((letter, i) => (
            <motion.span
              key={i}
              custom={i}
              variants={letterVariants}
              initial="hidden"
              animate="visible"
              style={{
                fontSize: 54,
                fontWeight: 800,
                color: i < BRAND.nameEco.length ? 'var(--primary)' : 'var(--text-primary)',
                fontFamily: 'var(--font-display)',
                letterSpacing: '-0.03em',
                display: 'inline-block',
              }}
            >
              {letter}
            </motion.span>
          ))}
        </div>

        <p style={{ color: 'var(--text-muted)', fontSize: 11, letterSpacing: '0.20em', fontFamily: 'var(--font-display)', marginBottom: 48 }}>
          {BRAND.tagline}
        </p>

        <div style={{ width: 220, height: 4, borderRadius: 99, overflow: 'hidden', background: 'var(--bg-overlay)' }}>
          <motion.div
            style={{
              height: '100%',
              width: `${progress}%`,
              background: 'linear-gradient(90deg,var(--primary),var(--primary-bright))',
              boxShadow: 'var(--shadow-orange-sm)',
              transition: 'width 0.016s linear',
            }}
          />
        </div>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: [0, 0.4, 0] }}
          transition={{ delay: 1, duration: 1.6, repeat: Infinity }}
          style={{
            position: 'absolute',
            bottom: 20,
            color: 'var(--text-muted)',
            fontSize: 10,
            letterSpacing: '0.18em',
            fontFamily: 'var(--font-body)',
          }}
        >
          {BRAND.loadingText || 'LOADING EXPERIENCE...'}
        </motion.p>
      </motion.div>
    </AnimatePresence>
  );
}
